CREATE TABLE products (
  id INTEGER PRIMARY KEY,
  name TEXT NOT NULL,
  price INTEGER
);

const schema = {
  fields: [{name: 'id', type: 'primary'}, {name: 'name', type: 'string'}, {name: 'price', type: 'number'}]
};
console.log(schema);

@Entity
public class Product {
  @Id
  @GeneratedValue
  private Integer id;
  private String name;
}
